   131	// FillDefault updates undefined fields in y with defaults from d (or built-in default), and overwrites with values from o.
   132	// Both d and o may be empty.
   133	//
   134	// Maps (`Env`) are being merged: first populated from d, overwritten by y, and again overwritten by o.
   135	// Slices (e.g. `Mounts`, `Provision`) are appended, starting with o, followed by y, and finally d. This
   136	// makes sure o takes priority over y over d, in cases it matters (e.g. `PortForwards`, where the first
   137	// matching rule terminates the search).
   138	//
   139	// Exceptions:
   140	//   - Mounts are appended in d, y, o order, but "merged" when the Location matches a previous entry;
   141	//     the highest priority Writable setting wins.
   142	//   - Networks are appended in d, y, o order
   143	//   - DNS are picked from the highest priority where DNS is not empty.
   144	//   - CACertificates Files and Certs are uniquely appended in d, y, o order
   145	func FillDefault(ctx context.Context, y, d, o *limatype.LimaYAML, filePath string, warn bool) {
   146		instDir := filepath.Dir(filePath)
   147	
   148		existingLimaVersion := ExistingLimaVersion(instDir)
   149	
   150		// OS has to be resolved before User
   151		if y.OS == nil {
   152			y.OS = d.OS
   153		}
   154		if o.OS != nil {
   155			y.OS = o.OS
   156		}
   157		y.OS = ptr.Of(ResolveOS(y.OS))
   158	
   159		if y.User.Name == nil {
   160			y.User.Name = d.User.Name
   161		}
   162		if y.User.Comment == nil {
   163			y.User.Comment = d.User.Comment
   164		}
   165		if y.User.Home == nil {
   166			y.User.Home = d.User.Home
   167		}
   168		if y.User.Shell == nil {
   169			y.User.Shell = d.User.Shell
   170		}
   171		if y.User.UID == nil {
   172			y.User.UID = d.User.UID
   173		}
   174		if o.User.Name != nil {
   175			y.User.Name = o.User.Name
   176		}
   177		if o.User.Comment != nil {
   178			y.User.Comment = o.User.Comment
   179		}
   180		if o.User.Home != nil {
   181			y.User.Home = o.User.Home
   182		}
   183		if o.User.Shell != nil {
   184			y.User.Shell = o.User.Shell
   185		}
   186		if o.User.UID != nil {
   187			y.User.UID = o.User.UID
   188		}
   189		if y.User.Name == nil {
   190			y.User.Name = ptr.Of(osutil.LimaUser(ctx, existingLimaVersion, warn, y.OS).Username)
   191			warn = false
   192		}
   193		if y.User.Comment == nil {
   194			y.User.Comment = ptr.Of(osutil.LimaUser(ctx, existingLimaVersion, warn, y.OS).Name)
   195			warn = false
   196		}
   197		if y.User.Home == nil {
   198			y.User.Home = ptr.Of(osutil.LimaUser(ctx, existingLimaVersion, warn, y.OS).HomeDir)
   199			warn = false
   200		}
   201		if y.User.Shell == nil {
   202			switch *y.OS {
   203			case limatype.FREEBSD:
   204				y.User.Shell = ptr.Of("/bin/sh")
   205			case limatype.DARWIN:
   206				y.User.Shell = ptr.Of("/bin/zsh")
   207			default:
   208				y.User.Shell = ptr.Of("/bin/bash")
   209			}
   210		}
   211		if y.User.UID == nil {
   212			uidString := osutil.LimaUser(ctx, existingLimaVersion, warn, y.OS).Uid
   213			if uid, err := strconv.ParseUint(uidString, 10, 32); err == nil {
   214				y.User.UID = ptr.Of(uint32(uid))
   215			} else {
   216				// This should never happen; LimaUser() makes sure that .Uid is numeric
   217				logrus.WithError(err).Warnf("Can't parse `user.uid` %q", uidString)
   218				y.User.UID = ptr.Of(uint32(1000))
   219			}
   220			// warn = false
   221		}
   222		if out, err := executeGuestTemplate(*y.User.Home, instDir, y.User, y.Param); err == nil {
   223			y.User.Home = ptr.Of(out.String())
   224		} else {
   225			logrus.WithError(err).Warnf("Couldn't process `user.home` value %q as a template", *y.User.Home)
   226		}
   227	
   228		if y.VMType == nil {
   229			y.VMType = d.VMType
   230		}
   231		if o.VMType != nil {
   232			y.VMType = o.VMType
   233		}
   234	
   235		if y.Arch == nil {
   236			y.Arch = d.Arch
   237		}
   238		if o.Arch != nil {
   239			y.Arch = o.Arch
   240		}
   241		y.Arch = ptr.Of(ResolveArch(y.Arch))
   242	
   243		y.Images = slices.Concat(o.Images, y.Images, d.Images)
   244		for i := range y.Images {
   245			img := &y.Images[i]
   246			if img.Arch == "" {
   247				img.Arch = *y.Arch
   248			}
   249			if img.Kernel != nil && img.Kernel.Arch == "" {
   250				img.Kernel.Arch = img.Arch
   251			}
   252			if img.Initrd != nil && img.Initrd.Arch == "" {
   253				img.Initrd.Arch = img.Arch
   254			}
   255		}
   256	
   257		if y.CPUs == nil {
   258			y.CPUs = d.CPUs
   259		}
   260		if o.CPUs != nil {
   261			y.CPUs = o.CPUs
   262		}
   263		if y.CPUs == nil || *y.CPUs == 0 {
   264			y.CPUs = ptr.Of(defaultCPUs())
   265		}
   266	
   267		if y.Memory == nil {
   268			y.Memory = d.Memory
   269		}
   270		if o.Memory != nil {
   271			y.Memory = o.Memory
   272		}
   273		if y.Memory == nil || *y.Memory == "" {
   274			y.Memory = ptr.Of(defaultMemoryAsString())
   275		}
   276	
   277		if y.Disk == nil {
   278			y.Disk = d.Disk
   279		}
   280		if o.Disk != nil {
   281			y.Disk = o.Disk
   282		}
   283		if y.Disk == nil || *y.Disk == "" {
   284			y.Disk = ptr.Of(defaultDiskSizeAsString())
   285		}
   286	
   287		y.AdditionalDisks = slices.Concat(o.AdditionalDisks, y.AdditionalDisks, d.AdditionalDisks)
   288	
   289		if y.Audio.Device == nil {
   290			y.Audio.Device = d.Audio.Device
   291		}
   292		if o.A<response clipped><NOTE>Due to the max output limit, only part of this file has been shown to you. You should retry this tool after you have searched inside the file with `grep -n` in order to find the line numbers of what you are looking for.</NOTE>ount.Writable {
   293					mounts[i].NineP.Cache = ptr.Of(Default9pCacheForRW)
   294				} else {
   295					mounts[i].NineP.Cache = ptr.Of(Default9pCacheForRO)
   296				}
   297			}
   298		}
   299	
   300		// Note: DNS lists are not combined; highest priority setting is picked
   301		if len(y.DNS) == 0 {
   302			y.DNS = d.DNS
   303		}
   304		if len(o.DNS) > 0 {
   305			y.DNS = o.DNS
   306		}
   307	
   308		env := make(map[string]string)
   309		maps.Copy(env, d.Env)
   310		maps.Copy(env, y.Env)
   311		maps.Copy(env, o.Env)
   312		y.Env = env
   313	
   314		param := make(map[string]string)
   315		maps.Copy(param, d.Param)
   316		maps.Copy(param, y.Param)
   317		maps.Copy(param, o.Param)
   318		y.Param = param
