   320		vmOpts := make(limatype.VMOpts)
   321		maps.Copy(vmOpts, d.VMOpts)
   322		maps.Copy(vmOpts, y.VMOpts)
   323		maps.Copy(vmOpts, o.VMOpts)
   324		y.VMOpts = vmOpts
   325	
   326		if y.CACertificates.RemoveDefaults == nil {
   327			y.CACertificates.RemoveDefaults = d.CACertificates.RemoveDefaults
   328		}
   329		if o.CACertificates.RemoveDefaults != nil {
   330			y.CACertificates.RemoveDefaults = o.CACertificates.RemoveDefaults
   331		}
   332		if y.CACertificates.RemoveDefaults == nil {
   333			y.CACertificates.RemoveDefaults = ptr.Of(false)
   334		}
   335	
   336		y.CACertificates.Files = unique(slices.Concat(d.CACertificates.Files, y.CACertificates.Files, o.CACertificates.Files))
   337		y.CACertificates.Certs = unique(slices.Concat(d.CACertificates.Certs, y.CACertificates.Certs, o.CACertificates.Certs))
   338	
   339		if y.NestedVirtualization == nil {
   340			y.NestedVirtualization = d.NestedVirtualization
   341		}
   342		if o.NestedVirtualization != nil {
   343			y.NestedVirtualization = o.NestedVirtualization
   344		}
   345		if y.NestedVirtualization == nil {
   346			y.NestedVirtualization = ptr.Of(false)
   347		}
   348	
   349		if y.Plain == nil {
   350			y.Plain = d.Plain
   351		}
   352		if o.Plain != nil {
   353			y.Plain = o.Plain
   354		}
   355		if y.Plain == nil {
   356			y.Plain = ptr.Of(false)
