   362	// ExistingLimaVersion returns empty if the instance was created with Lima prior to v0.20.
   363	func ExistingLimaVersion(instDir string) string {
   364		if !IsExistingInstanceDir(instDir) {
   365			return version.Version
   366		}
   367	
   368		limaVersionFile := filepath.Join(instDir, filenames.LimaVersion)
   369		if b, err := os.ReadFile(limaVersionFile); err == nil {
   370			return strings.TrimSpace(string(b))
   371		} else if !errors.Is(err, os.ErrNotExist) {
   372			logrus.WithError(err).Warnf("Failed to read %q", limaVersionFile)
   373		}
   374	
   375		return version.Version
   376	}
