   378	func fixUpForPlainMode(y *limatype.LimaYAML) {
   379		if !*y.Plain {
   380			return
   381		}
   382		deleteNonStaticPortForwards(&y.PortForwards)
   383		y.Mounts = nil
   384		y.Containerd.System = ptr.Of(false)
   385		y.Containerd.User = ptr.Of(false)
   386		y.TimeZone = ptr.Of("")
   387	}
