   389	// deleteNonStaticPortForwards removes all non-static port forwarding rules in case of Plain mode.
   390	func deleteNonStaticPortForwards(portForwards *[]limatype.PortForward) {
   391		staticPortForwards := make([]limatype.PortForward, 0, len(*portForwards))
   392		for _, rule := range *portForwards {
   393			if rule.Static {
   394				staticPortForwards = append(staticPortForwards, rule)
   395			}
   396		}
   397		*portForwards = staticPortForwards
   398	}
