   400	func executeGuestTemplate(format, instDir string, user limatype.User, param map[string]string) (bytes.Buffer, error) {
   401		tmpl, err := template.New("").Parse(format)
   402		if err == nil {
   403			name := filepath.Base(instDir)
   404			data := map[string]any{
   405				"Name":     name,
   406				"Hostname": hostname.FromInstName(name), // TODO: support customization
   407				"UID":      *user.UID,
   408				"User":     *user.Name,
   409				"Home":     *user.Home,
   410				"Param":    param,
   411			}
   412			var out bytes.Buffer
   413			err = tmpl.Execute(&out, data)
   414			if err == nil {
   415				return out, nil
   416			}
   417		}
   418		return bytes.Buffer{}, err
   419	}
   420	
   421	func executeHostTemplate(format, instDir string, param map[string]string) (bytes.Buffer, error) {
   422		tmpl, err := template.New("").Parse(format)
   423		if err == nil {
   424			limaHome, _ := dirnames.LimaDir()
   425			globalTempDir := "/tmp"
   426			if runtime.GOOS == "windows" {
   427				// On Windows the global temp directory "%SystemRoot%\Temp" (normally "C:\Windows\Temp")
   428				// is not writable by regular users.
   429				globalTempDir = os.TempDir()
   430			}
   431			data := map[string]any{
   432				"Dir":  instDir,
   433				"Name": filepath.Base(instDir),
   434				// TODO: add hostname fields for the host and the guest
   435				"UID":           currentUser.Uid,
   436				"User":          currentUser.Username,
   437				"Home":          userHomeDir,
   438				"Param":         param,
   439				"GlobalTempDir": globalTempDir,
   440				"TempDir":       os.TempDir(),
   441	
   442				"Instance": filepath.Base(instDir), // DEPRECATED, use `{{.Name}}`
   443				"LimaHome": limaHome,               // DEPRECATED, use `{{.Dir}}` instead of `{{.LimaHome}}/{{.Instance}}`
   444			}
   445			var out bytes.Buffer
   446			err = tmpl.Execute(&out, data)
   447			if err == nil {
   448				return out, nil
   449			}
   450		}
   451		return bytes.Buffer{}, err
   452	}
