   454	func FillPortForwardDefaults(rule *limatype.PortForward, instDir string, user limatype.User, param map[string]string) {
   455		if rule.Proto == "" {
   456			rule.Proto = limatype.ProtoAny
   457		}
   458		if rule.GuestIP == nil {
   459			if rule.GuestIPMustBeZero != nil && *rule.GuestIPMustBeZero {
   460				rule.GuestIP = net.IPv4zero
   461			} else {
   462				rule.GuestIP = IPv4loopback1
   463			}
   464		}
   465		if rule.GuestIPMustBeZero == nil {
   466			rule.GuestIPMustBeZero = ptr.Of(rule.GuestIP.Equal(net.IPv4zero))
   467		}
   468		if rule.HostIP == nil {
   469			rule.HostIP = IPv4loopback1
   470		}
   471		if rule.GuestPortRange[0] == 0 && rule.GuestPortRange[1] == 0 {
   472			if rule.GuestPort == 0 {
   473				rule.GuestPortRange[0] = 1
   474				rule.GuestPortRange[1] = 65535
   475			} else {
   476				rule.GuestPortRange[0] = rule.GuestPort
   477				rule.GuestPortRange[1] = rule.GuestPort
   478			}
   479		}
   480		if rule.GuestSocket != "" {
   481			if out, err := executeGuestTemplate(rule.GuestSocket, instDir, user, param); err == nil {
   482				rule.GuestSocket = out.String()
   483			} else {
   484				logrus.WithError(err).Warnf("Couldn't process guestSocket %q as a template", rule.GuestSocket)
   485			}
   486		}
   487		if rule.HostSocket != "" {
   488			if out, err := executeHostTemplate(rule.HostSocket, instDir, param); err == nil {
   489				rule.HostSocket = out.String()
   490			} else {
   491				logrus.WithError(err).Warnf("Couldn't process hostSocket %q as a template", rule.HostSocket)
   492			}
   493			if !filepath.IsAbs(rule.HostSocket) {
   494				rule.HostSocket = filepath.Join(instDir, filenames.SocketDir, rule.HostSocket)
   495			}
   496		} else if rule.HostPortRange[0] == 0 && rule.HostPortRange[1] == 0 {
   497			if rule.HostPort == 0 {
   498				rule.HostPortRange = rule.GuestPortRange
   499			} else {
   500				rule.HostPortRange[0] = rule.HostPort
   501				rule.HostPortRange[1] = rule.HostPort
   502			}
   503		}
   504	}
