   523	func IsExistingInstanceDir(dir string) bool {
   524		// existence of "lima.yaml" does not signify existence of the instance,
   525		// because the file is created during the initialization of the instance.
   526		for _, f := range []string{
   527			filenames.HostAgentStdoutLog, filenames.HostAgentStderrLog,
   528			filenames.VzIdentifier, filenames.Image, filenames.Disk, filenames.BaseDiskLegacy, filenames.DiffDiskLegacy, filenames.CIDataISO,
   529		} {
   530			file := filepath.Join(dir, f)
   531			if _, err := os.Lstat(file); !errors.Is(err, os.ErrNotExist) {
   532				return true
   533			}
   534		}
   535		return false
   536	}
