   134	// evalExprImpl evaluates tmpl.expr against one or more documents.
   135	// Called by evalExpr() and embedAllScripts() for single documents and merge() for 2 documents.
   136	func (tmpl *Template) evalExprImpl(prefix string, b []byte) error {
   137		var err error
   138		expr := prefix + tmpl.expr.String() + "| $a"
   139		tmpl.Bytes, err = yqutil.EvaluateExpression(expr, b)
   140		// Make sure the YAML ends with just a single newline
   141		tmpl.Bytes = append(bytes.TrimRight(tmpl.Bytes, "\n"), '\n')
   142		tmpl.Config = nil
   143		tmpl.expr.Reset()
   144		return tmpl.ClearOnError(err)
   145	}
