   286	// combineNetworks combines networks entries. The shared key is the interface name.
   287	func (tmpl *Template) combineNetworks() {
   288		const networks = "networks"
   289	
   290		interfaceIdx := make(map[string]int, len(tmpl.Config.Networks))
   291		for src := 0; src < len(tmpl.Config.Networks); {
   292			nw := tmpl.Config.Networks[src]
   293			var from, to int
   294			if nw.Interface == "*" {
   295				from = 0
   296				to = src - 1
   297			} else {
   298				if i, ok := interfaceIdx[nw.Interface]; ok {
   299					from = i
   300					to = i
   301				} else {
   302					if nw.Interface != "" {
   303						interfaceIdx[nw.Interface] = src
   304					}
   305					src++
   306					continue
   307				}
   308			}
   309			for dst := from; dst <= to; dst++ {
   310				dest := &tmpl.Config.Networks[dst]
   311				// Lima and Socket are mutually exclusive. Only copy base values if both are still unset.
   312				if dest.Lima == "" && dest.Socket == "" {
