   343	// yamlfmt will fail with a buffer overflow while trying to retain line breaks if the line
   344	// is longer than 64K. We will encode all text files that have a line that comes close.
   345	// maxLineLength is a constant; it is only a variable for the benefit of the unit tests.
   346	var maxLineLength = 65000
   347	
   348	// encodeScriptReason returns the reason why a script needs to be base64 encoded or the empty string if it doesn't.
   349	func encodeScriptReason(script string) string {
   350		start := 0
   351		line := 1
   352		for i, r := range script {
   353			if !(unicode.IsPrint(r) || r == '\n') {
   354				return fmt.Sprintf("unprintable character %q at offset %d", r, i)
   355			}
   356			// maxLineLength includes final newline
   357			if i-start >= maxLineLength {
   358				return fmt.Sprintf("line %d (offset %d) is longer than %d characters", line, start, maxLineLength)
   359			}
   360			if r == '\n' {
   361				line++
   362				start = i + 1
   363			}
   364		}
   365		return ""
   366	}
   367	
   368	// Break base64 strings into shorter chunks. Technically we could use maxLineLength here,
   369	// but shorter lines look better.
   370	const base64ChunkLength = 76
   371	
   372	// binaryString returns a base64 encoded version of the binary string, broken into chunks
   373	// of at most base64ChunkLength characters per line.
   374	func binaryString(s string) string {
   375		encoded := base64.StdEncoding.EncodeToString([]byte(s))
   376		if len(encoded) <= base64ChunkLength {
   377			return encoded
   378		}
   379	
   380		// Estimate capacity: encoded length + number of newlines
   381		lineCount := (len(encoded) + base64ChunkLength - 1) / base64ChunkLength
   382		builder := strings.Builder{}
   383		builder.Grow(len(encoded) + lineCount)
   384	
   385		for i := 0; i < len(encoded); i += base64ChunkLength {
   386			end := min(i+base64ChunkLength, len(encoded))
   387			builder.WriteString(encoded[i:end])
   388			builder.WriteByte('\n')
   389		}
   390	
   391		return builder.String()
   392	}
