   394	// updateScript replaces a "file" property with the actual script and then renames the field to newName ("script" or "content").
   395	func (tmpl *Template) updateScript(field string, idx int, newName, script, file string) {
   396		tag := ""
   397		if reason := encodeScriptReason(script); reason != "" {
   398			logrus.Infof("File %q is being base64 encoded: %s", file, reason)
   399			script = binaryString(script)
   400			tag = "!!binary"
   401		}
   402		entry := fmt.Sprintf("$a.%s[%d].file", field, idx)
   403		// Assign script to the "file" field and then rename it to "script" or "content".
   404		fmt.Fprintf(&tmpl.expr, "| (%s) = %q | (%s) tag = %q | (%s | key) = %q\n",
   405			entry, script, entry, tag, entry, newName)
   406	}
