   408	// embedAllScripts replaces all "provision" and "probes" file references with the actual script.
   409	func (tmpl *Template) embedAllScripts(ctx context.Context, embedAll bool) error {
   410		if err := tmpl.Unmarshal(); err != nil {
   411			return err
   412		}
   413		for i, p := range tmpl.Config.Probes {
   414			if p.File == nil {
   415				continue
   416			}
   417			// Don't overwrite existing script. This should throw an error during validation.
   418			if p.Script == nil || *p.Script != "" {
   419				continue
   420			}
   421			isTemplate, _ := SeemsTemplateURL(p.File.URL)
   422			if embedAll || !isTemplate {
   423				scriptTmpl, err := Read(ctx, "", p.File.URL)
   424				if err != nil {
   425					return err
   426				}
   427				tmpl.updateScript("probes", i, "script", string(scriptTmpl.Bytes), p.File.URL)
   428			}
   429		}
   430		for i, p := range tmpl.Config.Provision {
   431			if p.File == nil {
   432				continue
   433			}
   434			newName := "script"
   435			switch p.Mode {
   436			case limatype.ProvisionModeData:
   437				newName = "content"
   438				if p.Content != nil {
   439					continue
   440				}
   441			case limatype.ProvisionModeYQ:
   442				newName = "expression"
   443				if p.Expression != nil {
   444					continue
   445				}
   446			default:
   447				if p.Script != nil && *p.Script != "" {
   448					continue
   449				}
   450			}
   451			isTemplate, _ := SeemsTemplateURL(p.File.URL)
   452			if embedAll || !isTemplate {
   453				scriptTmpl, err := Read(ctx, "", p.File.URL)
   454				if err != nil {
   455					return err
   456				}
   457				tmpl.updateScript("provision", i, newName, string(scriptTmpl.Bytes), p.File.URL)
   458			}
   459		}
   460		return tmpl.evalExpr()
   461	}
