//go:build ignore

package main

import (
	"context"
	"fmt"
	"os"

	"github.com/lima-vm/lima/v2/pkg/limatmpl"
)

func main() {
	dir, _ := os.MkdirTemp("", "test-dns")
	defer os.RemoveAll(dir)
	os.Chdir(dir)

	// Test: Template with NO dns, base HAS dns
	os.WriteFile("base0.yaml", []byte("dns: [1.1.1.1, 8.8.8.8]\n"), 0600)

	tmpl := &limatmpl.Template{
		Bytes:   []byte("base: base0.yaml\nvmType: qemu\n"),
		Locator: "tmpl.yaml",
	}

	err := tmpl.Embed(context.Background(), false, false)
	if err != nil {
		fmt.Printf("ERROR: %v\n", err)
		os.Exit(1)
	}

	fmt.Printf("Result:\n%s\n", string(tmpl.Bytes))

	err = tmpl.Unmarshal()
	if err != nil {
		fmt.Printf("Unmarshal error: %v\n", err)
	}
	if tmpl.Config.DNS == nil {
		fmt.Println("DNS is nil!")
	} else if len(tmpl.Config.DNS) == 0 {
		fmt.Println("DNS is empty!")
	} else {
		fmt.Printf("DNS: %v\n", tmpl.Config.DNS)
	}
}
