)

func main() {
	documents := "vmType: qemu\n---\ndns: [1.1.1.1, 8.8.8.8]\n"

	// Test step by step
	steps := []struct{
		name string
		expr string
	}{
		{"step1: select a", `select(document_index == 0)`},
		{"step2: as $a", `select(document_index == 0) as $a`},
		{"step3: set $b", `select(document_index == 0) as $a | select(document_index == 1) as $b`},
		{"step4: $b as $c", `select(document_index == 0) as $a | select(document_index == 1) as $b | $b as $c`},
		{"step5: tag lists in $c", `select(document_index == 0) as $a | select(document_index == 1) as $b | $b as $c | $c | .. | select(tag == "!!seq") tag = "!!tag"`},
		{"step6: delpaths from $c", `select(document_index == 0) as $a | select(document_index == 1) as $b | $b as $c | $c | .. | select(tag == "!!seq") tag = "!!tag" | $c | delpaths([$a | .. | select(tag != "!!map") | path])`},
		{"step7: merge $a * $c", `select(document_index == 0) as $a | select(document_index == 1) as $b | $b as $c | $c | .. | select(tag == "!!seq") tag = "!!tag" | $c | delpaths([$a | .. | select(tag != "!!map") | path]) | $a * ($c // {}) as $a`},
	}

	for _, step := range steps {
		result, err := yqutil.EvaluateExpression(step.expr, []byte(documents))
		if err != nil {
			fmt.Fprintf(os.Stderr, "%s: ERROR: %v\n", step.name, err)
		} else {
			fmt.Printf("%s:\n%s\n\n", step.name, string(result))
		}
	}

	// Now let's also test: $a has dns set, $b has base dns - does delete work?
	documents2 := "dns: [1.1.1.1]\n---\ndns: [8.8.8.8, 1.2.3.4]\n"
	expr_del := `select(document_index == 0) as $a | select(document_index == 1) as $b | $a | select(.dns) | del($b.dns, $c.dns)`
	result, err := yqutil.EvaluateExpression(expr_del, []byte(documents2))
	if err != nil {
		fmt.Fprintf(os.Stderr, "delete test: ERROR: %v\n", err)
	} else {
		fmt.Printf("Delete test (a has dns):\n%s\n", string(result))
	}
}
