package main

import (
	"fmt"
	"os"

	"github.com/lima-vm/lima/v2/pkg/yqutil"
)

func main() {
	// Test: $a has NO dns, $b has dns. Simulate the full mergeDocuments script
	documents := "vmType: qemu\n---\ndns: [1.1.1.1, 8.8.8.8]\n"

	// Full mergeDocuments (without base-handling and comments-related parts)
	expr := `select(document_index == 0) as $a
| select(document_index == 1) as $b
| $b as $c
| $a | select(.dns) | del($b.dns, $c.dns)
| $c | .. | select(tag == "!!seq") tag = "!!tag"
| $c | delpaths([$a | .. | select(tag != "!!map") | path])
| $a * ($c // {}) as $a
| $a | .. | select(tag == "!!seq" and (path[0] | test("^(base|provision|probes)$") | not)) |= (. + (path[] as $p ireduce ($b; .[$p])))
| $a | .. | select(tag == "!!seq" and (path[0] | test("^(base|provision|probes)$"))) |= ((path[] as $p ireduce ($b; .[$p])) + .)
| $a | .. | select(tag == "!!tag") tag = ""`

	result, err := yqutil.EvaluateExpression(expr, []byte(documents))
	if err != nil {
		fmt.Fprintf(os.Stderr, "ERROR: %v\n", err)
		os.Exit(1)
	}
	fmt.Printf("Result (a has NO dns, b has dns):\n%s\n", string(result))

	// Now test: $a HAS dns (should keep a's dns)
	documents2 := "dns: [1.1.1.1]\n---\ndns: [8.8.8.8, 1.2.3.4]\n"
	result2, err := yqutil.EvaluateExpression(expr, []byte(documents2))
	if err != nil {
		fmt.Fprintf(os.Stderr, "ERROR: %v\n", err)
		os.Exit(1)
	}
	fmt.Printf("Result (a HAS dns, b has dns):\n%s\n", string(result2))
}
