//go:build ignore

package main

import (
	"fmt"
	"os"

	"github.com/lima-vm/lima/v2/pkg/yqutil"
)

func main() {
	mainYAML := "base: base0.yaml\n"
	baseYAML := "dns: [1.1.1.1, 8.8.8.8]\n"
	documents := mainYAML + "---\n" + baseYAML

	tests := []struct {
		name string
		expr string
	}{
		{"just select a", `select(document_index == 0) as $a | select(document_index == 1) as $b | $b as $c | $a * ($c // {}) as $a | $a | .. | select(tag == "!!tag") tag = ""`},
		{"with del base[0]", `select(document_index == 0) as $a | select(document_index == 1) as $b | $b as $c | $a | select(.base | tag == "!!seq") | del(.base[0]) | $a * ($c // {}) as $a | $a | .. | select(tag == "!!tag") tag = ""`},
		{"with del base str", `select(document_index == 0) as $a | select(document_index == 1) as $b | $b as $c | $a | select(.base | tag == "!!seq") | del(.base[0]) | $a | select(.base | (tag == "!!seq" and length == 0)) | del(.base) | $a | select(.base | tag == "!!str") | del(.base) | $a * ($c // {}) as $a | $a | .. | select(tag == "!!tag") tag = ""`},
		{"with dns del", `select(document_index == 0) as $a | select(document_index == 1) as $b | $b as $c | $a | select(.base | tag == "!!seq") | del(.base[0]) | $a | select(.base | (tag == "!!seq" and length == 0)) | del(.base) | $a | select(.base | tag == "!!str") | del(.base) | $a | select(.dns) | del($b.dns, $c.dns) | $a * ($c // {}) as $a | $a | .. | select(tag == "!!tag") tag = ""`},
		{"with tag", `select(document_index == 0) as $a | select(document_index == 1) as $b | $b as $c | $a | select(.base | tag == "!!seq") | del(.base[0]) | $a | select(.base | (tag == "!!seq" and length == 0)) | del(.base) | $a | select(.base | tag == "!!str") | del(.base) | $a | select(.dns) | del($b.dns, $c.dns) | $c | .. | select(tag == "!!seq") tag = "!!tag" | $a * ($c // {}) as $a | $a | .. | select(tag == "!!tag") tag = ""`},
		{"with delpaths", `select(document_index == 0) as $a | select(document_index == 1) as $b | $b as $c | $a | select(.base | tag == "!!seq") | del(.base[0]) | $a | select(.base | (tag == "!!seq" and length == 0)) | del(.base) | $a | select(.base | tag == "!!str") | del(.base) | $a | select(.dns) | del($b.dns, $c.dns) | $c | .. | select(tag == "!!seq") tag = "!!tag" | $c | delpaths([$a | .. | select(tag != "!!map") | path]) | $a * ($c // {}) as $a | $a | .. | select(tag == "!!tag") tag = ""`},
	}

	for _, t := range tests {
		out, err := yqutil.EvaluateExpression(t.expr, []byte(documents))
		if err != nil {
			fmt.Fprintf(os.Stderr, "%s: ERROR: %v\n", t.name, err)
		} else {
			fmt.Printf("%s:\n%s\n\n", t.name, string(out))
		}
	}
}
