package main

import (
	"context"
	"fmt"
	"os"
	"strings"

	"github.com/lima-vm/lima/v2/pkg/limatmpl"
)

func main() {
	dir, _ := os.MkdirTemp("", "test-hr")
	defer os.RemoveAll(dir)
	os.Chdir(dir)

	// Case 1: Template with NO hostResolver, base HAS hostResolver
	os.WriteFile("base0.yaml", []byte("hostResolver:\n  enabled: false\n"), 0600)
	tmpl := &limatmpl.Template{
		Bytes:   []byte("base: base0.yaml\n"),
		Locator: "tmpl.yaml",
	}
	err := tmpl.Embed(context.Background(), false, false)
	if err != nil {
		fmt.Printf("ERROR: %v\n", err)
		os.Exit(1)
	}
	fmt.Printf("Case 1 (no hostResolver in template, hostResolver in base):\n%s\n", strings.TrimSpace(string(tmpl.Bytes)))
	tmpl.Unmarshal()
	if tmpl.Config.HostResolver.Enabled != nil {
		fmt.Printf("hostResolver.Enabled: %v\n", *tmpl.Config.HostResolver.Enabled)
		if *tmpl.Config.HostResolver.Enabled {
			fmt.Println("FAIL: hostResolver.enabled should be false from base!")
			os.Exit(1)
		}
		fmt.Println("PASS: hostResolver propagated from base")
	} else {
		fmt.Println("FAIL: hostResolver not propagated at all!")
		os.Exit(1)
	}
}
